begin; create extension if not exists pg_trgm;
create table public.flashcard_decks(id uuid primary key default gen_random_uuid(),owner_id uuid not null references auth.users(id) on delete cascade,title text not null check(char_length(btrim(title)) between 1 and 120),course_name text not null check(char_length(btrim(course_name)) between 1 and 100),normalized_course_name text not null default '',description text not null default '' check(char_length(description)<=1000),topic_tags text[] not null default '{}' check(public.community_tags_valid(topic_tags)),visibility text not null default 'private' check(visibility in('private','shared')),status text not null default 'active' check(status in('active','hidden','removed')),target_date date,linked_assignment_id text,source_deck_id uuid references public.flashcard_decks(id) on delete set null,is_favorite boolean not null default false,search_document tsvector not null default ''::tsvector,created_at timestamptz not null default now(),updated_at timestamptz not null default now(),published_at timestamptz);
create table public.flashcards(id uuid primary key default gen_random_uuid(),deck_id uuid not null references public.flashcard_decks(id) on delete cascade,front text not null check(char_length(btrim(front)) between 1 and 500),back text not null check(char_length(btrim(back)) between 1 and 2000),hint text not null default '' check(char_length(hint)<=500),explanation text not null default '' check(char_length(explanation)<=2000),position int not null check(position>=0 and position<500),created_at timestamptz not null default now(),updated_at timestamptz not null default now(),unique(deck_id,position));
create table public.flashcard_user_progress(user_id uuid not null references auth.users(id) on delete cascade,card_id uuid not null references public.flashcards(id) on delete cascade,review_count int not null default 0,again_count int not null default 0,hard_count int not null default 0,good_count int not null default 0,easy_count int not null default 0,last_rating text check(last_rating is null or last_rating in('Again','Hard','Good','Easy')),confidence_status text not null default 'New' check(confidence_status in('New','Learning','Familiar','Strong')),is_starred boolean not null default false,last_reviewed_at timestamptz,created_at timestamptz not null default now(),updated_at timestamptz not null default now(),primary key(user_id,card_id));
create table public.flashcard_study_sessions(id uuid primary key default gen_random_uuid(),user_id uuid not null references auth.users(id) on delete cascade,deck_id uuid not null references public.flashcard_decks(id) on delete cascade,started_at timestamptz not null,completed_at timestamptz,cards_reviewed int not null default 0,again_count int not null default 0,hard_count int not null default 0,good_count int not null default 0,easy_count int not null default 0,duration_seconds int not null default 0,session_completed boolean not null default false);
create table public.flashcard_deck_ratings(deck_id uuid references public.flashcard_decks(id) on delete cascade,user_id uuid references auth.users(id) on delete cascade,rating text not null check(rating in('Helpful','Not Helpful')),created_at timestamptz not null default now(),primary key(deck_id,user_id));
create table public.flashcard_deck_reports(id uuid primary key default gen_random_uuid(),deck_id uuid not null references public.flashcard_decks(id) on delete cascade,reporter_id uuid not null references auth.users(id) on delete cascade,reason text not null check(reason in('Active test questions or answer key','Copied or copyrighted material','Incorrect or misleading content','Personal information','Harassment or harmful content','Spam','Other')),details text check(details is null or char_length(details)<=1000),created_at timestamptz not null default now(),unique(deck_id,reporter_id));
create table public.flashcard_deck_favorites(deck_id uuid references public.flashcard_decks(id) on delete cascade,user_id uuid references auth.users(id) on delete cascade,created_at timestamptz not null default now(),primary key(deck_id,user_id));
create table public.community_post_decks(post_id uuid primary key references public.community_posts(id) on delete cascade,deck_id uuid not null references public.flashcard_decks(id) on delete cascade,created_at timestamptz not null default now());
create or replace function public.flashcard_prepare_deck()returns trigger language plpgsql set search_path=public,pg_temp as $$begin new.normalized_course_name=lower(regexp_replace(btrim(new.course_name),'\s+',' ','g'));new.search_document=to_tsvector('english'::regconfig,coalesce(new.title,'')||' '||coalesce(new.course_name,'')||' '||coalesce(new.description,'')||' '||coalesce(array_to_string(new.topic_tags,' '),'') );if new.visibility='shared' and(old is null or old.visibility='private')then new.published_at=coalesce(new.published_at,now());end if;new.updated_at=now();return new;end$$;
create trigger flashcard_deck_prepare before insert or update of title,course_name,description,topic_tags,visibility on public.flashcard_decks for each row execute function public.flashcard_prepare_deck();
create or replace function public.flashcard_touch()returns trigger language plpgsql as $$begin new.updated_at=now();return new;end$$;create trigger flashcard_touch_card before update on public.flashcards for each row execute function public.flashcard_touch();
create index flash_deck_owner_idx on public.flashcard_decks(owner_id,updated_at desc);create index flash_deck_shared_idx on public.flashcard_decks(visibility,status,published_at desc);create index flash_deck_course_idx on public.flashcard_decks(normalized_course_name);create index flash_deck_search_idx on public.flashcard_decks using gin(search_document);create index flash_deck_target_idx on public.flashcard_decks(target_date);create index flash_deck_assignment_idx on public.flashcard_decks(linked_assignment_id);create index flash_deck_source_idx on public.flashcard_decks(source_deck_id);create index flash_cards_position_idx on public.flashcards(deck_id,position);create index flash_progress_user_idx on public.flashcard_user_progress(user_id,card_id);create index flash_ratings_deck_idx on public.flashcard_deck_ratings(deck_id);create index flash_reports_deck_idx on public.flashcard_deck_reports(deck_id);
alter table public.flashcard_decks enable row level security;alter table public.flashcards enable row level security;alter table public.flashcard_user_progress enable row level security;alter table public.flashcard_study_sessions enable row level security;alter table public.flashcard_deck_ratings enable row level security;alter table public.flashcard_deck_reports enable row level security;alter table public.flashcard_deck_favorites enable row level security;alter table public.community_post_decks enable row level security;
create policy flash_decks_read on public.flashcard_decks for select to authenticated using(owner_id=auth.uid()or(visibility='shared'and status='active')or public.is_community_moderator(auth.uid()));create policy flash_decks_owner_delete on public.flashcard_decks for delete to authenticated using(owner_id=auth.uid());create policy flash_cards_read on public.flashcards for select to authenticated using(exists(select 1 from public.flashcard_decks d where d.id=deck_id and(d.owner_id=auth.uid()or(d.visibility='shared'and d.status='active')or public.is_community_moderator(auth.uid()))));create policy flash_progress_own on public.flashcard_user_progress for all to authenticated using(user_id=auth.uid())with check(user_id=auth.uid());create policy flash_sessions_own on public.flashcard_study_sessions for select to authenticated using(user_id=auth.uid());create policy flash_ratings_own on public.flashcard_deck_ratings for all to authenticated using(user_id=auth.uid())with check(user_id=auth.uid()and not exists(select 1 from public.flashcard_decks d where d.id=deck_id and d.owner_id=auth.uid()));create policy flash_reports_insert on public.flashcard_deck_reports for insert to authenticated with check(reporter_id=auth.uid());create policy flash_reports_mod on public.flashcard_deck_reports for select to authenticated using(public.is_community_moderator(auth.uid()));create policy flash_favorites_own on public.flashcard_deck_favorites for all to authenticated using(user_id=auth.uid())with check(user_id=auth.uid());create policy flash_links_read on public.community_post_decks for select to authenticated using(exists(select 1 from public.flashcard_decks d where d.id=deck_id and d.visibility='shared'and d.status='active'));create policy flash_links_owner on public.community_post_decks for all to authenticated using(exists(select 1 from public.community_posts p,public.flashcard_decks d where p.id=post_id and d.id=deck_id and p.author_id=auth.uid()and d.owner_id=auth.uid()))with check(exists(select 1 from public.community_posts p,public.flashcard_decks d where p.id=post_id and d.id=deck_id and p.author_id=auth.uid()and d.owner_id=auth.uid()and d.visibility='shared'and d.status='active'));
revoke all on public.flashcard_decks,public.flashcards,public.flashcard_user_progress,public.flashcard_study_sessions,public.flashcard_deck_ratings,public.flashcard_deck_reports,public.flashcard_deck_favorites,public.community_post_decks from anon;grant select,delete on public.flashcard_decks to authenticated;grant select on public.flashcards to authenticated;grant select,insert,update,delete on public.flashcard_user_progress,public.flashcard_deck_ratings,public.flashcard_deck_favorites to authenticated;grant select,insert on public.flashcard_deck_reports to authenticated;grant select,insert,update,delete on public.community_post_decks to authenticated;
create or replace function public.save_flashcard_deck(deck_payload jsonb)returns uuid language plpgsql security definer set search_path=public,pg_temp as $$declare did uuid;cid uuid;card jsonb;kept_ids uuid[]:='{}';begin if auth.uid()is null then raise exception'Authentication required';end if;if jsonb_array_length(coalesce(deck_payload->'cards','[]'))>500 then raise exception'Maximum 500 cards';end if;did=nullif(deck_payload->>'id','')::uuid;if did is null then if(select count(*)from public.flashcard_decks where owner_id=auth.uid())>=100 then raise exception'Maximum 100 decks';end if;insert into public.flashcard_decks(owner_id,title,course_name,description,topic_tags,visibility,target_date,linked_assignment_id,is_favorite)values(auth.uid(),deck_payload->>'title',deck_payload->>'course_name',coalesce(deck_payload->>'description',''),array(select jsonb_array_elements_text(coalesce(deck_payload->'topic_tags','[]'))),coalesce(deck_payload->>'visibility','private'),nullif(deck_payload->>'target_date','')::date,nullif(deck_payload->>'linked_assignment_id',''),coalesce((deck_payload->>'is_favorite')::boolean,false))returning id into did;else if not exists(select 1 from public.flashcard_decks where id=did and owner_id=auth.uid())then raise exception'Not authorized';end if;update public.flashcard_decks set title=deck_payload->>'title',course_name=deck_payload->>'course_name',description=coalesce(deck_payload->>'description',''),topic_tags=array(select jsonb_array_elements_text(coalesce(deck_payload->'topic_tags','[]'))),visibility=coalesce(deck_payload->>'visibility','private'),target_date=nullif(deck_payload->>'target_date','')::date,linked_assignment_id=nullif(deck_payload->>'linked_assignment_id',''),is_favorite=coalesce((deck_payload->>'is_favorite')::boolean,false)where id=did;end if;for card in select*from jsonb_array_elements(coalesce(deck_payload->'cards','[]'))loop if btrim(card->>'front')<>''and btrim(card->>'back')<>''then cid=coalesce(nullif(card->>'id','')::uuid,gen_random_uuid());if exists(select 1 from public.flashcards where id=cid and deck_id<>did)then cid=gen_random_uuid();end if;insert into public.flashcards(id,deck_id,front,back,hint,explanation,position)values(cid,did,card->>'front',card->>'back',coalesce(card->>'hint',''),coalesce(card->>'explanation',''),(card->>'position')::int)on conflict(id)do update set front=excluded.front,back=excluded.back,hint=excluded.hint,explanation=excluded.explanation,position=excluded.position where flashcards.deck_id=did;kept_ids=array_append(kept_ids,cid);end if;end loop;delete from public.flashcards where deck_id=did and not(id=any(kept_ids));return did;end$$;revoke all on function public.save_flashcard_deck(jsonb)from public;grant execute on function public.save_flashcard_deck(jsonb)to authenticated;
create or replace function public.flashcard_get_deck(target_deck_id uuid)returns jsonb language sql stable security definer set search_path=public,pg_temp as $$select to_jsonb(d)||jsonb_build_object('cards',coalesce((select jsonb_agg(to_jsonb(c)order by c.position)from public.flashcards c where c.deck_id=d.id),'[]'::jsonb))from public.flashcard_decks d where d.id=target_deck_id and(d.owner_id=auth.uid()or(d.visibility='shared'and d.status='active')or public.is_community_moderator(auth.uid()))$$;revoke all on function public.flashcard_get_deck(uuid)from public;grant execute on function public.flashcard_get_deck(uuid)to authenticated;
create or replace function public.flashcard_my_decks(search_text text default'',course_filter text default null,sort_by text default'updated',page_number int default 0,page_size int default 20)returns setof public.flashcard_decks language sql stable security invoker as $$select d from public.flashcard_decks d where owner_id=auth.uid()and(search_text=''or search_document@@websearch_to_tsquery('english',search_text))and(course_filter is null or course_name=course_filter)order by case when sort_by='alpha'then title end,case when sort_by='target'then target_date end,updated_at desc limit least(page_size,50)offset greatest(page_number,0)*least(page_size,50)$$;
create or replace function public.flashcard_shared_decks(search_text text default'',course_filter text default null,sort_by text default'helpful',page_number int default 0,page_size int default 20)returns table(id uuid,owner_id uuid,title text,course_name text,description text,topic_tags text[],visibility text,status text,target_date date,updated_at timestamptz,published_at timestamptz,card_count bigint,understanding_percent int)language sql stable security definer as $$select d.id,d.owner_id,d.title,d.course_name,d.description,d.topic_tags,d.visibility,d.status,d.target_date,d.updated_at,d.published_at,count(distinct c.id),0 from public.flashcard_decks d left join public.flashcards c on c.deck_id=d.id left join public.flashcard_deck_ratings r on r.deck_id=d.id where d.visibility='shared'and d.status='active'and(search_text=''or d.search_document@@websearch_to_tsquery('english',search_text))and(course_filter is null or d.course_name=course_filter)group by d.id order by case when sort_by='helpful'then count(r.*)filter(where r.rating='Helpful')end desc,d.published_at desc limit least(page_size,50)offset greatest(page_number,0)*least(page_size,50)$$;
create or replace function public.copy_flashcard_deck(source_id uuid)returns uuid language plpgsql security definer as $$declare nid uuid;begin if(select count(*)from public.flashcard_decks where owner_id=auth.uid())>=100 then raise exception'Maximum 100 decks';end if;insert into public.flashcard_decks(owner_id,title,course_name,description,topic_tags,source_deck_id)select auth.uid(),title,course_name,description,topic_tags,id from public.flashcard_decks where id=source_id and visibility='shared'and status='active'returning id into nid;insert into public.flashcards(deck_id,front,back,hint,explanation,position)select nid,front,back,hint,explanation,position from public.flashcards where deck_id=source_id;return nid;end$$;
create or replace function public.complete_flashcard_session(target_deck_id uuid,started_at timestamptz,reviews jsonb)returns uuid language plpgsql security definer as $$declare sid uuid;r jsonb;rating text;begin if jsonb_array_length(reviews)>500 then raise exception'Invalid session';end if;for r in select*from jsonb_array_elements(reviews)loop rating=r->>'rating';insert into public.flashcard_user_progress(user_id,card_id,review_count,again_count,hard_count,good_count,easy_count,last_rating,confidence_status,last_reviewed_at)values(auth.uid(),(r->>'card_id')::uuid,1,(rating='Again')::int,(rating='Hard')::int,(rating='Good')::int,(rating='Easy')::int,rating,case rating when'Again'then'Learning'when'Hard'then'Learning'when'Good'then'Familiar'else'Familiar'end,now())on conflict(user_id,card_id)do update set review_count=flashcard_user_progress.review_count+1,again_count=flashcard_user_progress.again_count+(rating='Again')::int,hard_count=flashcard_user_progress.hard_count+(rating='Hard')::int,good_count=flashcard_user_progress.good_count+(rating='Good')::int,easy_count=flashcard_user_progress.easy_count+(rating='Easy')::int,last_rating=rating,confidence_status=case when rating='Again'then'Learning'when rating='Hard'then'Learning'when rating='Good'then'Familiar'when flashcard_user_progress.review_count>1 then'Strong'else'Familiar'end,last_reviewed_at=now(),updated_at=now();end loop;insert into public.flashcard_study_sessions(user_id,deck_id,started_at,completed_at,cards_reviewed,again_count,hard_count,good_count,easy_count,duration_seconds,session_completed)select auth.uid(),target_deck_id,started_at,now(),jsonb_array_length(reviews),count(*)filter(where x->>'rating'='Again'),count(*)filter(where x->>'rating'='Hard'),count(*)filter(where x->>'rating'='Good'),count(*)filter(where x->>'rating'='Easy'),least(86400,greatest(0,extract(epoch from now()-started_at)::int)),jsonb_array_length(reviews)>0 from jsonb_array_elements(reviews)x returning id into sid;return sid;end$$;
grant execute on function public.flashcard_my_decks(text,text,text,int,int),public.flashcard_shared_decks(text,text,text,int,int),public.copy_flashcard_deck(uuid),public.complete_flashcard_session(uuid,timestamptz,jsonb)to authenticated;
create or replace function public.flashcard_hide_after_reports()returns trigger language plpgsql security definer as $$begin update public.flashcard_decks set status='hidden'where id=new.deck_id and status='active'and(select count(distinct reporter_id)from public.flashcard_deck_reports where deck_id=new.deck_id)>=3;return new;end$$;create trigger flashcard_reports_hide after insert on public.flashcard_deck_reports for each row execute function public.flashcard_hide_after_reports();

create table public.flashcard_xp_events(id uuid primary key default gen_random_uuid(),user_id uuid not null references auth.users(id)on delete cascade,event_key text not null,xp int not null check(xp between 1 and 100),event_type text not null,card_id uuid references public.flashcards(id)on delete cascade,session_id uuid references public.flashcard_study_sessions(id)on delete cascade,event_day date not null default current_date,created_at timestamptz not null default now(),unique(user_id,event_key));
create table public.flashcard_badge_unlocks(user_id uuid not null references auth.users(id)on delete cascade,badge_id text not null,unlocked_at timestamptz not null default now(),primary key(user_id,badge_id));
create index flash_xp_user_day_idx on public.flashcard_xp_events(user_id,event_day);create index flash_badges_user_idx on public.flashcard_badge_unlocks(user_id);
alter table public.flashcard_xp_events enable row level security;alter table public.flashcard_badge_unlocks enable row level security;create policy flash_xp_own_read on public.flashcard_xp_events for select to authenticated using(user_id=auth.uid());create policy flash_badges_own_read on public.flashcard_badge_unlocks for select to authenticated using(user_id=auth.uid());grant select on public.flashcard_xp_events,public.flashcard_badge_unlocks to authenticated;revoke all on public.flashcard_xp_events,public.flashcard_badge_unlocks from anon;

create or replace function public.rate_flashcard_deck(target_deck_id uuid,new_rating text)returns jsonb language plpgsql security definer set search_path=public,pg_temp as $$declare deck_owner uuid;helpful_total int;begin select owner_id into deck_owner from public.flashcard_decks where id=target_deck_id and visibility='shared'and status='active'and owner_id<>auth.uid();if deck_owner is null then raise exception'Deck cannot be rated';end if;if new_rating is null then delete from public.flashcard_deck_ratings where deck_id=target_deck_id and user_id=auth.uid();elsif new_rating in('Helpful','Not Helpful')then insert into public.flashcard_deck_ratings(deck_id,user_id,rating)values(target_deck_id,auth.uid(),new_rating)on conflict(deck_id,user_id)do update set rating=excluded.rating;else raise exception'Invalid rating';end if;select count(*)into helpful_total from public.flashcard_deck_ratings where deck_id=target_deck_id and rating='Helpful';if helpful_total>=1 then insert into public.flashcard_badge_unlocks(user_id,badge_id)values(deck_owner,'flash-first-helpful')on conflict do nothing;end if;if helpful_total>=10 then insert into public.flashcard_badge_unlocks(user_id,badge_id)values(deck_owner,'flash-ten-helpful')on conflict do nothing;end if;return(select jsonb_build_object('helpful_count',count(*)filter(where rating='Helpful'),'not_helpful_count',count(*)filter(where rating='Not Helpful'),'current_rating',max(rating)filter(where user_id=auth.uid()))from public.flashcard_deck_ratings where deck_id=target_deck_id);end$$;
create or replace function public.report_flashcard_deck(target_deck_id uuid,report_reason text,report_details text default null)returns void language plpgsql security definer set search_path=public,pg_temp as $$begin if not exists(select 1 from public.flashcard_decks where id=target_deck_id and visibility='shared'and status='active'and owner_id<>auth.uid())then raise exception'Deck cannot be reported';end if;insert into public.flashcard_deck_reports(deck_id,reporter_id,reason,details)values(target_deck_id,auth.uid(),report_reason,nullif(btrim(report_details),''));end$$;
create or replace function public.flashcard_moderation_queue()returns table(id uuid,owner_id uuid,title text,course_name text,description text,status text,created_at timestamptz,report_count bigint,reports jsonb,cards jsonb)language plpgsql security definer set search_path=public,pg_temp as $$begin if not public.is_community_moderator(auth.uid())then raise exception'Moderator access required';end if;return query select d.id,d.owner_id,d.title,d.course_name,d.description,d.status,d.created_at,count(distinct r.reporter_id),coalesce(jsonb_agg(distinct jsonb_build_object('reason',r.reason,'details',r.details,'created_at',r.created_at))filter(where r.id is not null),'[]'::jsonb),coalesce((select jsonb_agg(jsonb_build_object('front',c.front,'back',c.back,'hint',c.hint,'explanation',c.explanation)order by c.position)from public.flashcards c where c.deck_id=d.id),'[]'::jsonb)from public.flashcard_decks d left join public.flashcard_deck_reports r on r.deck_id=d.id where d.status='hidden'or r.id is not null group by d.id order by count(distinct r.reporter_id)desc,d.created_at;end$$;
create or replace function public.moderate_flashcard_deck(target_deck_id uuid,new_status text,clear_reports boolean default true)returns void language plpgsql security definer set search_path=public,pg_temp as $$begin if not public.is_community_moderator(auth.uid())then raise exception'Moderator access required';end if;if new_status not in('active','hidden','removed')then raise exception'Invalid status';end if;update public.flashcard_decks set status=new_status where id=target_deck_id;if clear_reports then delete from public.flashcard_deck_reports where deck_id=target_deck_id;end if;end$$;
create or replace function public.attach_deck_to_community_post(target_post_id uuid,target_deck_id uuid)returns void language plpgsql security definer set search_path=public,pg_temp as $$begin if not exists(select 1 from public.community_posts where id=target_post_id and author_id=auth.uid())or not exists(select 1 from public.flashcard_decks where id=target_deck_id and owner_id=auth.uid()and visibility='shared'and status='active')then raise exception'Only your active Shared Deck may be attached';end if;insert into public.community_post_decks(post_id,deck_id)values(target_post_id,target_deck_id)on conflict(post_id)do update set deck_id=excluded.deck_id;end$$;
create or replace function public.add_cards_to_owned_deck(target_deck_id uuid,new_cards jsonb)returns int language plpgsql security definer set search_path=public,pg_temp as $$declare existing_count int;added int;begin if not exists(select 1 from public.flashcard_decks where id=target_deck_id and owner_id=auth.uid())then raise exception'Not authorized';end if;select count(*)into existing_count from public.flashcards where deck_id=target_deck_id;if existing_count+jsonb_array_length(new_cards)>500 then raise exception'Maximum 500 cards';end if;insert into public.flashcards(deck_id,front,back,hint,explanation,position)select target_deck_id,x->>'front',x->>'back',coalesce(x->>'hint',''),coalesce(x->>'explanation',''),existing_count+ordinality-1 from jsonb_array_elements(new_cards)with ordinality as rows(x,ordinality)where btrim(x->>'front')<>''and btrim(x->>'back')<>'';get diagnostics added=row_count;return added;end$$;
create or replace function public.unlink_assignment_flashcards(target_assignment_id text)returns int language plpgsql security definer set search_path=public,pg_temp as $$declare changed int;begin update public.flashcard_decks set linked_assignment_id=null where owner_id=auth.uid()and linked_assignment_id=target_assignment_id;get diagnostics changed=row_count;return changed;end$$;
create or replace function public.link_flashcard_deck_assignment(target_deck_id uuid,target_assignment_id text)returns void language plpgsql security definer set search_path=public,pg_temp as $$begin update public.flashcard_decks set linked_assignment_id=nullif(target_assignment_id,'')where id=target_deck_id and owner_id=auth.uid();if not found then raise exception'Not authorized';end if;end$$;
create or replace function public.flashcard_assignment_decks(target_assignment_id text)returns table(id uuid,title text,card_count bigint,understanding_percent int,target_date date)language sql stable security definer set search_path=public,pg_temp as $$select d.id,d.title,count(distinct c.id),coalesce(round(100.0*count(distinct p.card_id)filter(where p.confidence_status in('Familiar','Strong'))/nullif(count(distinct c.id),0)),0)::int,d.target_date from public.flashcard_decks d left join public.flashcards c on c.deck_id=d.id left join public.flashcard_user_progress p on p.card_id=c.id and p.user_id=auth.uid()where d.owner_id=auth.uid()and d.linked_assignment_id=target_assignment_id group by d.id$$;
create or replace function public.flashcard_deck_rating_summary(target_deck_id uuid)returns jsonb language sql stable security definer set search_path=public,pg_temp as $$select jsonb_build_object('helpful_count',count(*)filter(where rating='Helpful'),'not_helpful_count',count(*)filter(where rating='Not Helpful'),'current_rating',max(rating)filter(where user_id=auth.uid()))from public.flashcard_deck_ratings where deck_id=target_deck_id and exists(select 1 from public.flashcard_decks where id=target_deck_id and visibility='shared'and status='active')$$;
create or replace function public.flashcard_add_xp(target_user uuid,target_key text,target_xp int,target_type text,target_card uuid default null,target_session uuid default null)returns int language plpgsql security definer set search_path=public,pg_temp as $$declare earned int;remaining int;begin select greatest(0,100-coalesce(sum(xp),0))into remaining from public.flashcard_xp_events where user_id=target_user and event_day=current_date;earned=least(target_xp,remaining);if earned<=0 then return 0;end if;insert into public.flashcard_xp_events(user_id,event_key,xp,event_type,card_id,session_id)values(target_user,target_key,earned,target_type,target_card,target_session)on conflict(user_id,event_key)do nothing;if not found then return 0;end if;return earned;end$$;revoke all on function public.flashcard_add_xp(uuid,text,int,text,uuid,uuid)from public;
create or replace function public.flashcard_unlock_badges(target_user uuid)returns text[] language plpgsql security definer set search_path=public,pg_temp as $$declare ids text[]:='{}';unique_cards int;study_days int;streak int;begin select count(distinct card_id),count(distinct event_day)into unique_cards,study_days from public.flashcard_xp_events where user_id=target_user and card_id is not null;select count(*)into streak from(select distinct event_day from public.flashcard_xp_events where user_id=target_user and event_day>=current_date-interval'6 days')d;ids=array_remove(array[case when exists(select 1 from public.flashcard_decks where owner_id=target_user)then'flash-first-deck'end,case when exists(select 1 from public.flashcard_study_sessions where user_id=target_user and session_completed)then'flash-first-session'end,case when unique_cards>=25 then'flash-25-cards'end,case when unique_cards>=100 then'flash-100-cards'end,case when unique_cards>=500 then'flash-500-cards'end,case when study_days>=3 then'flash-three-days'end,case when streak>=7 then'flash-seven-day-streak'end,case when exists(select 1 from public.flashcard_decks where owner_id=target_user and visibility='shared'and published_at is not null)then'flash-first-shared'end,case when exists(select 1 from public.flashcard_deck_ratings r join public.flashcard_decks d on d.id=r.deck_id where d.owner_id=target_user and r.rating='Helpful')then'flash-first-helpful'end,case when(select count(*)from public.flashcard_deck_ratings r join public.flashcard_decks d on d.id=r.deck_id where d.owner_id=target_user and r.rating='Helpful')>=10 then'flash-ten-helpful'end,case when exists(select 1 from public.community_post_decks l join public.flashcard_decks d on d.id=l.deck_id where d.owner_id=target_user)then'flash-community-creator'end],null);insert into public.flashcard_badge_unlocks(user_id,badge_id)select target_user,unnest(ids)on conflict do nothing;return ids;end$$;revoke all on function public.flashcard_unlock_badges(uuid)from public;
create or replace function public.complete_flashcard_session_v2(target_deck_id uuid,started_at timestamptz,reviews jsonb)returns jsonb language plpgsql security definer set search_path=public,pg_temp as $$declare sid uuid;r jsonb;rating text;old_status text;new_status text;duration int;earned int:=0;meaningful boolean;before_target boolean;begin if auth.uid()is null or jsonb_array_length(reviews)not between 1 and 500 or not exists(select 1 from public.flashcard_decks where id=target_deck_id and(owner_id=auth.uid()or(visibility='shared'and status='active')))then raise exception'Invalid study session';end if;duration=least(86400,greatest(0,extract(epoch from now()-started_at)::int));meaningful=duration>=greatest(10,jsonb_array_length(reviews)*2);select target_date is not null and target_date>=current_date into before_target from public.flashcard_decks where id=target_deck_id;insert into public.flashcard_study_sessions(user_id,deck_id,started_at,completed_at,cards_reviewed,again_count,hard_count,good_count,easy_count,duration_seconds,session_completed)select auth.uid(),target_deck_id,started_at,now(),jsonb_array_length(reviews),count(*)filter(where x->>'rating'='Again'),count(*)filter(where x->>'rating'='Hard'),count(*)filter(where x->>'rating'='Good'),count(*)filter(where x->>'rating'='Easy'),duration,meaningful from jsonb_array_elements(reviews)x returning id into sid;for r in select*from jsonb_array_elements(reviews)loop if not exists(select 1 from public.flashcards where id=(r->>'card_id')::uuid and deck_id=target_deck_id)then raise exception'Card does not belong to deck';end if;rating=r->>'rating';select confidence_status into old_status from public.flashcard_user_progress where user_id=auth.uid()and card_id=(r->>'card_id')::uuid;new_status=case when rating in('Again','Hard')then'Learning'when rating='Good'then'Familiar'when coalesce((select review_count from public.flashcard_user_progress where user_id=auth.uid()and card_id=(r->>'card_id')::uuid),0)>1 then'Strong'else'Familiar'end;insert into public.flashcard_user_progress(user_id,card_id,review_count,again_count,hard_count,good_count,easy_count,last_rating,confidence_status,last_reviewed_at)values(auth.uid(),(r->>'card_id')::uuid,1,(rating='Again')::int,(rating='Hard')::int,(rating='Good')::int,(rating='Easy')::int,rating,new_status,now())on conflict(user_id,card_id)do update set review_count=flashcard_user_progress.review_count+1,again_count=flashcard_user_progress.again_count+(rating='Again')::int,hard_count=flashcard_user_progress.hard_count+(rating='Hard')::int,good_count=flashcard_user_progress.good_count+(rating='Good')::int,easy_count=flashcard_user_progress.easy_count+(rating='Easy')::int,last_rating=rating,confidence_status=new_status,last_reviewed_at=now(),updated_at=now();if meaningful then earned=earned+public.flashcard_add_xp(auth.uid(),'review:'||(r->>'card_id')||':'||current_date,2,'daily_card_review',(r->>'card_id')::uuid,sid);if(old_status='Learning'and new_status='Familiar')or(old_status='Familiar'and new_status='Strong')then earned=earned+public.flashcard_add_xp(auth.uid(),'improve:'||(r->>'card_id')||':'||new_status,5,'confidence_improvement',(r->>'card_id')::uuid,sid);end if;end if;end loop;if meaningful then earned=earned+public.flashcard_add_xp(auth.uid(),'session:'||sid,10,'meaningful_session',null,sid);earned=earned+public.flashcard_add_xp(auth.uid(),'complete:'||sid,5,'session_complete',null,sid);if before_target then earned=earned+public.flashcard_add_xp(auth.uid(),'target:'||sid,5,'before_target',null,sid);insert into public.flashcard_badge_unlocks(user_id,badge_id)select auth.uid(),'flash-before-target'where before_target on conflict do nothing;end if;end if;return jsonb_build_object('session_id',sid,'xp_earned',earned,'total_xp',(select coalesce(sum(xp),0)from public.flashcard_xp_events where user_id=auth.uid()),'badges',public.flashcard_unlock_badges(auth.uid()),'meaningful',meaningful);end$$;
create or replace function public.flashcard_reward_summary()returns jsonb language sql stable security definer set search_path=public,pg_temp as $$select jsonb_build_object('total_xp',coalesce((select sum(xp)from public.flashcard_xp_events where user_id=auth.uid()),0),'today_xp',coalesce((select sum(xp)from public.flashcard_xp_events where user_id=auth.uid()and event_day=current_date),0),'daily_cap',100,'badges',coalesce((select jsonb_agg(badge_id)from public.flashcard_badge_unlocks where user_id=auth.uid()),'[]'::jsonb))$$;
drop function public.flashcard_my_decks(text,text,text,int,int);
create function public.flashcard_my_decks(search_text text default'',course_filter text default null,sort_by text default'updated',page_number int default 0,page_size int default 20,group_filter text default'all')returns table(id uuid,owner_id uuid,title text,course_name text,description text,topic_tags text[],visibility text,status text,target_date date,linked_assignment_id text,is_favorite boolean,created_at timestamptz,updated_at timestamptz,card_count bigint,new_count bigint,learning_count bigint,familiar_count bigint,strong_count bigint,starred_count bigint,total_sessions bigint,last_studied_at timestamptz,understanding_percent int)language sql stable security definer set search_path=public,pg_temp as $$select d.id,d.owner_id,d.title,d.course_name,d.description,d.topic_tags,d.visibility,d.status,d.target_date,d.linked_assignment_id,d.is_favorite,d.created_at,d.updated_at,count(distinct c.id),count(distinct c.id)filter(where coalesce(p.review_count,0)=0),count(distinct c.id)filter(where p.confidence_status='Learning'),count(distinct c.id)filter(where p.confidence_status='Familiar'),count(distinct c.id)filter(where p.confidence_status='Strong'),count(distinct c.id)filter(where p.is_starred),count(distinct s.id),max(s.completed_at),coalesce(round(100.0*count(distinct c.id)filter(where p.confidence_status in('Familiar','Strong'))/nullif(count(distinct c.id),0)),0)::int from public.flashcard_decks d left join public.flashcards c on c.deck_id=d.id left join public.flashcard_user_progress p on p.card_id=c.id and p.user_id=auth.uid()left join public.flashcard_study_sessions s on s.deck_id=d.id and s.user_id=auth.uid()and s.session_completed where d.owner_id=auth.uid()and(search_text=''or d.search_document@@websearch_to_tsquery('english',search_text))and(course_filter is null or d.course_name=course_filter)and(group_filter='all'or group_filter='favorites'and d.is_favorite or group_filter='recent'and exists(select 1 from public.flashcard_study_sessions recent where recent.deck_id=d.id and recent.user_id=auth.uid()))group by d.id order by case when sort_by='alpha'then d.title end,case when sort_by='target'then d.target_date end,case when sort_by='studied'then max(s.completed_at)end desc,d.updated_at desc limit least(page_size,50)offset greatest(page_number,0)*least(page_size,50)$$;
create or replace function public.set_flashcard_deck_favorite(target_deck_id uuid,favorite boolean)returns void language plpgsql security definer set search_path=public,pg_temp as $$begin update public.flashcard_decks set is_favorite=favorite where id=target_deck_id and owner_id=auth.uid();if not found then raise exception'Not authorized';end if;end$$;
create or replace function public.set_flashcard_star(target_card_id uuid,starred boolean)returns void language plpgsql security definer set search_path=public,pg_temp as $$begin if auth.uid()is null or not exists(select 1 from public.flashcards c join public.flashcard_decks d on d.id=c.deck_id where c.id=target_card_id and(d.owner_id=auth.uid()or(d.visibility='shared'and d.status='active')))then raise exception'Not authorized';end if;insert into public.flashcard_user_progress(user_id,card_id,is_starred)values(auth.uid(),target_card_id,starred)on conflict(user_id,card_id)do update set is_starred=excluded.is_starred,updated_at=now();end$$;
create or replace function public.delete_flashcard_deck(target_deck_id uuid)returns void language plpgsql security definer set search_path=public,pg_temp as $$begin delete from public.flashcard_decks where id=target_deck_id and owner_id=auth.uid();if not found then raise exception'Not authorized';end if;end$$;
create or replace function public.flashcard_badge_after_deck_change()returns trigger language plpgsql security definer set search_path=public,pg_temp as $$begin insert into public.flashcard_badge_unlocks(user_id,badge_id)values(new.owner_id,'flash-first-deck')on conflict do nothing;if new.visibility='shared'and new.status='active'then insert into public.flashcard_badge_unlocks(user_id,badge_id)values(new.owner_id,'flash-first-shared')on conflict do nothing;end if;return new;end$$;
create trigger flashcard_deck_badges after insert or update of visibility,status on public.flashcard_decks for each row execute function public.flashcard_badge_after_deck_change();
create or replace function public.flashcard_badge_after_attachment()returns trigger language plpgsql security definer set search_path=public,pg_temp as $$declare owner uuid;begin select author_id into owner from public.community_posts where id=new.post_id;insert into public.flashcard_badge_unlocks(user_id,badge_id)values(owner,'flash-community-creator')on conflict do nothing;return new;end$$;
create trigger flashcard_community_creator_badge after insert on public.community_post_decks for each row execute function public.flashcard_badge_after_attachment();
revoke all on function public.rate_flashcard_deck(uuid,text),public.report_flashcard_deck(uuid,text,text),public.flashcard_moderation_queue(),public.moderate_flashcard_deck(uuid,text,boolean),public.attach_deck_to_community_post(uuid,uuid),public.add_cards_to_owned_deck(uuid,jsonb),public.unlink_assignment_flashcards(text),public.link_flashcard_deck_assignment(uuid,text),public.flashcard_assignment_decks(text),public.flashcard_deck_rating_summary(uuid),public.complete_flashcard_session_v2(uuid,timestamptz,jsonb),public.flashcard_reward_summary(),public.flashcard_my_decks(text,text,text,int,int,text),public.set_flashcard_deck_favorite(uuid,boolean),public.set_flashcard_star(uuid,boolean),public.delete_flashcard_deck(uuid)from public;grant execute on function public.rate_flashcard_deck(uuid,text),public.report_flashcard_deck(uuid,text,text),public.flashcard_moderation_queue(),public.moderate_flashcard_deck(uuid,text,boolean),public.attach_deck_to_community_post(uuid,uuid),public.add_cards_to_owned_deck(uuid,jsonb),public.unlink_assignment_flashcards(text),public.link_flashcard_deck_assignment(uuid,text),public.flashcard_assignment_decks(text),public.flashcard_deck_rating_summary(uuid),public.complete_flashcard_session_v2(uuid,timestamptz,jsonb),public.flashcard_reward_summary(),public.flashcard_my_decks(text,text,text,int,int,text),public.set_flashcard_deck_favorite(uuid,boolean),public.set_flashcard_star(uuid,boolean),public.delete_flashcard_deck(uuid)to authenticated;
commit;
